 1	import * as React from 'react';
 2	import { RowComponentType } from '@odf/shared/table';
 3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 4	import { TFunction } from 'react-i18next';
 5	import { Label } from '@patternfly/react-core';
 6	import { Tr, Td, ActionsColumn } from '@patternfly/react-table';
 7	import { ObjectCrFormat } from '../../../types';
 8	import { DownloadAndPreviewState } from '../download-and-preview/download-and-preview';
 9	import { getInlineActionsItems } from '../objects-list/table-components';
10	
11	export const getColumnNames = (t: TFunction) => [
12	  t('Version ID'),
13	  t('Size'),
14	  t('Last modified'),
15	  '',
16	];
17	
18	export const getHeaderColumns = (t: TFunction) => {
19	  const columnNames = getColumnNames(t);
20	
21	  return [
22	    { columnName: columnNames[0] },
23	    { columnName: columnNames[1] },
24	    { columnName: columnNames[2] },
25	    { columnName: columnNames[3] },
26	  ];
27	};
28	
29	export const ObjectVersionsTableRow: React.FC<
30	  RowComponentType<ObjectCrFormat>
31	> = ({ row: object, extraProps }) => {
32	  const { t } = useCustomTranslation();
33	
34	  const {
35	    launcher,
36	    bucketName,
37	    s3Client,
38	    foldersPath,
39	    setDeleteResponse,
40	    refreshTokens,
41	    closeObjectSidebar,
42	  } = extraProps;
43	
44	  const [downloadAndPreview, setDownloadAndPreview] =
45	    React.useState<DownloadAndPreviewState>({
46	      isDownloading: false,
47	      isPreviewing: false,
48	    });
49	
50	  const isLatest = object?.isLatest;
51	  const isDeleteMarker = object?.isDeleteMarker;
52	  const columnNames = getColumnNames(t);
53	  const actionItems = getInlineActionsItems(
54	    t,
55	    launcher,
56	    bucketName,
57	    object,
58	    s3Client,
59	    downloadAndPreview,
60	    setDownloadAndPreview,
61	    foldersPath,
62	    setDeleteResponse,
63	    refreshTokens,
64	    closeObjectSidebar,
65	    true,
66	    undefined
67	  );
68	
69	  return (
70	    <Tr>
71	      <Td dataLabel={columnNames[0]}>
72	        <span>
73	          {object.apiResponse.versionId}
74	          {isLatest && (
75	            <Label color="purple" className="pf-v6-u-ml-xs" isCompact>
76	              {t('Latest')}
77	            </Label>
78	          )}
79	          {isDeleteMarker && (
80	            <Label color="purple" className="pf-v6-u-ml-xs" isCompact>
81	              {t('Delete marker')}
82	            </Label>
83	          )}
84	        </span>
85	      </Td>
86	      <Td dataLabel={columnNames[1]}>{object.apiResponse.size}</Td>
87	      <Td dataLabel={columnNames[2]}>{object.apiResponse.lastModified}</Td>
88	      <Td dataLabel={columnNames[3]} isActionCell>
89	        <ActionsColumn items={actionItems} />
90	      </Td>
91	    </Tr>
92	  );
93	};

